//pendiente por configurar
import {
  BotonTema,
  Header2,
  Footer,
  Github,
} from "../reutilizables/componentes";

import { useState } from "react";

function AdminRegistros() {
  const [turno, setturno] = useState("");
  const [fecha, setfecha] = useState("");
  const [produccion, setproduccion] = useState(null);
  const [baches, setbaches] = useState([]);

  const handleConsultarRegistro = async () => {
    try {
      if (!turno || !fecha) {
        alert("Faltan campos requeridos");
        return;
      }
      const res = await fetch(
        `http://localhost:4000/api/consultarRegistro?turno=${turno}&fecha=${fecha}`,
        {
          method: "GET",
        },
      );

      const data = await res.json();

      if (!res.ok) {
        alert(data.error || "Error al obtener registros");
        setproduccion(null);
        setbaches([]);
        return;
      }
      const { results, resultsB } = data;

      if (!results || results.length === 0) {
        alert("No se encontraron registros");
        setproduccion(null);
        setbaches([]);
        return;
      }
      setproduccion(results[0]);
      setbaches(resultsB);
    } catch (error) {
      alert("Error al consultar registro: falla de conexion");
    }
  };

  const handleEliminarR = async () => {
    if (!produccion) {
      alert("No hay ningun registro cargado");
      return;
    }

    if (
      !window.confirm(
        "Seguro que quieres eliminar este registro? revisa nuevamente los datos si es necesario",
      )
    ) {
      return;
    }

    const idProduccion = produccion.idProduccion;
    const res = await fetch(
      `http://localhost:4000/api/eliminarRegistro/${idProduccion}`,
      {
        method: "DELETE",
      },
    );

    const data = await res.json();

    if (!res.ok) {
      alert(data.error || "Error al eliminar el usuario");
      return;
    }

    alert("Registro eliminado exitosamente");
    setturno("");
    setfecha("");
    setproduccion(null);
    setbaches([]);
  };
  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onClick={() => window.history.back()}>
            Volver
          </button>
        </header>
        <Header2 />
        <section id="content">
          <label>
            Turno:
            <select
              id="turno"
              onChange={(e) => setturno(e.target.value)}
              value={turno}
            >
              <option value={""}>-- Seleccione el turno</option>
              <option value={"Turno 1"}>Turno 1</option>
              <option value={"Turno 2"}>Turno 2</option>
            </select>
          </label>
          <label>
            Ingrese la Fecha:
            <input
              type="date"
              placeholder="Ingrese la fecha"
              value={fecha}
              onChange={(e) => setfecha(e.target.value)}
            ></input>
          </label>

          <button
            id="consultar"
            className="principales"
            onClick={handleConsultarRegistro}
          >
            consultar registro por fecha
          </button>
          {produccion && (
            <div>
              <h4>Detalles de produccion:</h4>
              <p>
                <strong>Turno:</strong>
                {produccion.turno}
              </p>
              <p>
                <strong>Fecha:</strong>
                {produccion.fecha_prod}
              </p>
              <p>
                <strong>Proveedor de rinde:</strong>
                {produccion.proveedor_rinde}
              </p>
              <p>
                <strong>Lote del rinde:</strong>
                {produccion.lote_rinde}
              </p>
              <p>
                <strong>Canecas de rinde utilizadas:</strong>
                {produccion.num_canecas_rinde}
              </p>
              <p>
                <strong>Litros de rinde utilizados:</strong>
                {produccion.litros_caneca_rinde}
              </p>
              <p>
                <strong>Griego descolgado recibido:</strong>
                {produccion.griego_inicio}
              </p>
              <p>
                <strong>Griego agitado recibido:</strong>
                {produccion.agitado_inicio}
              </p>
              <p>
                <strong>Canecas de griego gastadas:</strong>
                {produccion.suma_baches}
              </p>
              <p>
                <strong>Canecas agitadas entregadas:</strong>
                {produccion.agitadas_final}
              </p>
              <p>
                <strong>Canecas descolgadas entregadas:</strong>
                {produccion.descolgadas_final}
              </p>
            </div>
          )}

          <section id="registroBaches">
            <h4>Lista de baches: </h4>
            {baches.length > 0 ? (
              <ul className="listas">
                {baches.map((bache) => (
                  <li key={bache.idBache}>
                    <p>
                      <strong>Proveedor:</strong>
                      {bache.proveedor}
                    </p>
                    <p>
                      <strong>Lote:</strong>
                      {bache.lote}
                    </p>
                    <p>
                      <strong>Canecas:</strong>
                      {bache.canecas}
                    </p>
                    <p>
                      <strong>Kilos totales:</strong>
                      {bache.kilos_bache}
                    </p>
                    <p>
                      <strong>Grego entregado a planta:</strong>
                      {bache.griego_entregado}
                    </p>
                    <p>
                      <strong>Kilos entregados:</strong>
                      {bache.entregado_kilos}
                    </p>
                    <p>
                      <strong>Saldo remanente:</strong>
                      {bache.saldo_remanente}
                    </p>
                  </li>
                ))}
              </ul>
            ) : (
              "NO HAY BACHES REGISTRADOS"
            )}
          </section>
          {produccion && (
            <button
              id="borrar"
              className="secundarios"
              onClick={handleEliminarR}
            >
              borrar registro
            </button>
          )}
        </section>
        <Footer />
      </div>
      <Github />
    </div>
  );
}
export default AdminRegistros;
